#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

__kernel void benchmark_func(const class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);
  const size_t lid = get_local_id(0);
  const size_t gsize = get_global_size(0);
  const size_t lsize = get_local_size(0);
  const size_t group = get_group_id(0);

  const class_T zero = seed - seed;
  class_T sum = zero;

#ifdef BLOCK_STRIDED
  const size_t first_index =
      group * lsize * (size_t)ELEMENTS_PER_THREAD * (size_t)FUSION_DEGREE + lid;
#else
  const size_t first_index = gid;
#endif

  for (uint fusion = 0; fusion < (uint)FUSION_DEGREE; ++fusion) {
#ifdef BLOCK_STRIDED
    const size_t base =
        group * lsize * (size_t)ELEMENTS_PER_THREAD * (size_t)FUSION_DEGREE +
        (size_t)fusion * lsize * (size_t)ELEMENTS_PER_THREAD + lid;
#else
    const size_t base =
        gid + (size_t)fusion * gsize * (size_t)ELEMENTS_PER_THREAD;
#endif

    for (uint i = 0; i < (uint)ELEMENTS_PER_THREAD; ++i) {
#ifdef BLOCK_STRIDED
      const size_t idx = base + (size_t)i * lsize;
#else
      const size_t idx = base + (size_t)i * gsize;
#endif

      class_T t = data[idx];
      for (uint j = 0; j < (uint)COMPUTE_ITERATIONS; ++j) {
        t = t * t + seed;
      }
      sum = sum + t;
    }
  }

  data[first_index] = sum;
}
